VALUES
  ('heelevel3-5ff21eeb-moex-00234', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '稅捐稽徵法第24條第1項第1款前段規定：「納稅義務人欠繳應納稅捐者，稅捐稽徵機關得 就納稅義務人相當於應繳稅捐數額之財產，通知有關機關，不得為移轉或設定他項權利……」 下列敘述何者正確？', '["主管稽徵機關依該法規定所為之禁止處分，為行政罰法之其他種類之行政罰", "納稅義務人對於主管稽徵機關之禁止處分不服時，可依行政執行法第9條規定向該管稽徵 機關聲明異議", "主管稽徵機關對於禁止處分之作成並沒有裁量權限", "主管稽徵機關所為之禁止處分具有形式上之確定力後，納稅義務人得依行政程序法第 128 條規定申請行政程序之再開以為救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00235', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列對於稅捐優惠之敘述何者錯誤？', '["稅法或其他法律為特定政策所規定之稅捐優惠，應明定實施年限並以達成合理之政策目的 為限，不得過度", "稅捐優惠之擬訂，應舉行公聽會並提出稅式支出評估", "最低稅負制度之引進，即在避免因稅捐優惠之過度而導致稅捐負擔之不公平", "依據所得稅法第4條規定，個人及營利事業出售土地之交易所得免納所得稅，係稅捐優惠 之明文化規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00236', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '檢舉逃漏稅捐或其他違反稅法規定之情事，經查明屬實，且裁罰確定並收到罰鍰者，稅捐稽 徵機關應以收到之罰鍰提成核發獎金與舉發人。該一獎金占罰鍰比例最高限度為：', '["5%", "10%", "15%", "20%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00237', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依據納稅者權利保護法第 4 條第 1 項規定：「納稅者為維持自己及受扶養親屬享有符合人性 尊嚴之基本生活所需之費用，不得加以課稅。」下列敘述，何者正確？', '["所稱維持基本生活所需之費用，指納稅者本人、配偶及受扶養親屬人數計算之免稅額及扣 除額加上基本生活費差額之合計數", "所稱維持基本生活所需之費用，指納稅者本人、配偶及受扶養親屬人數計算之免稅額及扣 除額之合計數", "所稱維持基本生活所需之費用，指標準扣除額應對準社會救助法中貧窮線之基準", "所稱維持基本生活所需之費用，指納稅者本人、配偶及受扶養親屬人數計算之免稅額、財 產交易損失及薪資所得特別扣除額加上基本生活費差額之合計數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00238', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '德國人甲為海德堡大學法律系三年級學生，於2022年1月寒假期間來臺灣之A法律事務所 實習兩個月，實習完後隨即返回德國參加國家考試。有關其於A法律事務所實習期間所獲得 之薪資，下列敘述何者正確？', '["甲非為居住於中華民國境內之自然人，我國對其所得沒有課稅權", "甲為居住於中華民國境內之自然人，我國對其全球所得有課稅權", "甲之實習薪資須依照我國所得稅法之規定為就源扣繳", "甲之實習薪資屬於中華民國來源所得，我國是否有課稅權須依照臺德所簽訂之稅捐協定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00239', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列法條之論據基礎，何者並非基於防堵稅捐規避之考量？', '["所得稅法第14條第1項第5類規定：「財產出租，其約定之租金，顯較當地一般租金為低， 稽徵機關得參照當地一般租金調整計算租賃收入。」", "所得稅法第66條之9第1項規定：「自87年度起至106年度止，營利事業當年度之盈餘 未作分配者，應就該未分配盈餘加徵百分之十營利事業所得稅；自107年度起，營利事業 當年度之盈餘未作分配者，應就該未分配盈餘加徵百分之五營利事業所得稅。」", "所得稅法第39條第1項規定：「以往年度營業之虧損，不得列入本年度計算。但公司組織 之營利事業，會計帳冊簿據完備，虧損及申報扣除年度均使用第77條所稱藍色申報書或經 會計師查核簽證，並如期申報者，得將經該管稽徵機關核定之前十年內各期虧損，自本年 純益額中扣除後，再行核課。」", "所得稅法第43條之2第1項規定：「自100年度起，營利事業對關係人之負債占業主權益 超過一定比率者，超過部分之利息支出不得列為費用或損失。」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00240', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列之立論基礎，何者並非基於實質課稅原則？', '["司法院釋字第565號解釋理由書：「憲法第7條平等原則並非指絕對、機械之形式上平等， 而係保障人民在法律上地位實質平等。依租稅平等原則納稅義務人固應按其實質稅負能力， 負擔應負之稅捐。」", "財政部81年2月20日台財稅第810759763號函：「經營六合彩賭博之收入其未經沒入部 分，核屬所得稅法第14條第1項第9類之其他所得，應以其收入額減除成本及必要費用後 之餘額為所得額，合併課徵綜合所得稅。」", "所得稅法第3條之3第1項第1款規定：「信託財產於左列各款信託關係人間，基於信託 關係移轉或為其他處分者，不課徵所得稅：一、因信託行為成立，委託人與受託人間。」", "所得稅法第14條第1項第5類規定：「設定定期之永佃權及地上權取得之各種所得，視為 租賃所得。」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00241', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '父甲將其名下位於新北市之土地以新臺幣（下同）800 萬元賣予其子乙（該筆土地之公告現 值為1,000萬元），並請國稅局核發非屬贈與財產同意移轉證明書等，經該局依其主張核發移 轉證明在案。然該局嗣後查得，本交易之買賣價款並無實際支付之事實。下列對於系爭案例 之法律評價，何者正確？', '["甲乙之財產交易，構成租稅規避，國稅局應請求甲繳納所規避之贈與稅", "甲乙之財產交易，構成租稅規避，國稅局應請求甲繳納所規避之贈與稅外，並處以所規避 稅額一定倍數之罰鍰", "甲乙之財產交易，構成稅捐逃漏，國稅局應核定所逃漏之稅款，並處以所漏稅額一定倍數 之罰鍰", "甲乙之財產交易，構成稅捐逃漏罪，法院可處1,000萬元以下之罰金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00242', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-c325224a', 'sub-heelevel3-5ff21eeb-06', NULL, 'essay', '關於「行政法之法源」，行政程序法是否有規定？並請分別舉例說明
「判例」、「大法庭裁定」及「自治法規」等，是否均屬行政法之法源？
（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "ac95c54f5357", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政程序法、行政罰法及行政執行法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00243', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-c325224a', 'sub-heelevel3-5ff21eeb-06', NULL, 'essay', '甲受行政處罰，但因未居住於戶籍地址，且郵寄送達時亦無家人在場，
致未收到裁處書，最後被依行政程序法第 74 條規定：「（第 1 項）送達，
不能依前 2 條規定為之者，得將文書寄存送達地之地方自治或警察機
關，並作送達通知書兩份，一份黏貼於應受送達人住居所、事務所、營
業所或其就業處所門首，另一份交由鄰居轉交或置於該送達處所信箱或
其他適當位置，以為送達。（第 2 項）前項情形，由郵政機關為送達者，
得將文書寄存於送達地之郵政機關。（第 3 項）寄存機關自收受寄存文
書之日起，應保存 3 個月。」為寄存送達。
請問：行政罰法針對「裁處書」之送達，有無具體規定？並依憲法解釋
說明寄存送達與一般送達、補充送達或留置送達之關聯性？行政程序法
第 74 條規定所設寄存送達之程序及方式，是否符合憲法正當法律程序
原則之要求？對甲權益之影響，是否在合法之範圍內？（40 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "ac95c54f5357", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政程序法、行政罰法及行政執行法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
